class UnitConversion { static double lpmToM3s(double lpm)=>lpm/1000/60;static double m3sToLpm(double m3s)=>m3s*1000*60;static double lpmToGpm(double lpm)=>lpm/3.785411784;static double gpmToLpm(double gpm)=>gpm*3.785411784;static double m3hToLpm(double m3h)=>m3h*1000/60;static double lpmToM3h(double lpm)=>lpm*60/1000;static double rtToKw(double rt)=>rt*3.517;static double kwToRt(double kw)=>kw/3.517;static double kwToKcalH(double kw)=>kw*860.42065;static double kcalHToKw(double kcalh)=>kcalh/860.42065;static double cfmToCmh(double cfm)=>cfm*1.69901082;static double cmhToCfm(double cmh)=>cmh/1.69901082;static double velocityMps({required double flowM3s,required double areaM2})=>flowM3s/areaM2;static double coolingKwFromLpmDeltaT({required double lpm,required double deltaTC})=>lpm*4.186*deltaTC/60;static double lpmFromCoolingKwDeltaT({required double kw,required double deltaTC})=>kw*60/4.186/deltaTC;}
